replacements.new:
// Find the last grapheme in the text before cursor
const graphemes = [...this.segment(beforeCursor, "grapheme")];
const lastGrapheme = graphemes[graphemes.length - 1];
const whitespaceRun = beforeCursor.match(/[ \t]{5,}$/);
const graphemeLength = whitespaceRun?.[0].length ?? (lastGrapheme ? lastGrapheme.segment.length : 1);
const isPastedSegmented = whitespaceRun ? null : PASTE_MARKER_SINGLE.exec(lastGrapheme.segment);
